import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a single string to handle escaped "\\n" sequences in test data
        String input = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Replace escaped newlines ("\\n") with spaces, then also replace real newlines with spaces
        input = input.replace("\\n", " ");
        input = input.replace('\n', ' ');
        StringTokenizer st = new StringTokenizer(input);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            int[] c = new int[N];
            long[] w = new long[N];
            for (int i = 0; i < N; i++) {
                c[i] = Integer.parseInt(st.nextToken());
            }
            for (int i = 0; i < N; i++) {
                w[i] = Long.parseLong(st.nextToken());
            }
            Map<Integer, Integer> lastPos = new HashMap<>();
            int left = 0;
            long curSum = 0;
            long best = Long.MIN_VALUE;
            for (int right = 0; right < N; right++) {
                int col = c[right];
                Integer prev = lastPos.get(col);
                if (prev != null && prev >= left) {
                    // Move left pointer just after previous occurrence, subtracting weights
                    while (left <= prev) {
                        curSum -= w[left];
                        left++;
                    }
                }
                curSum += w[right];
                if (curSum > best) best = curSum;
                lastPos.put(col, right);
            }
            sb.append(best).append('\n');
        }
        System.out.print(sb.toString());
    }
}

